import React, { useEffect, useState } from "react";
import axios from "axios";
import toast from "react-hot-toast";

export default function AdminDashboard() {
  const [activeTab, setActiveTab] = useState("users");
  const [data, setData] = useState([]);
  const token = localStorage.getItem("token");

  // Fetch data from here
  const fetchData = async (type) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/admin/${type}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setData(res.data);
    } catch (err) {
      toast.error("Error fetching data");
    }
  };

  useEffect(() => {
    fetchData(activeTab);
  }, [activeTab]);

  // Delete from here
  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/admin/${activeTab}/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      toast.success("Deleted Successfully");
      fetchData(activeTab);
    } catch (err) {
      toast.error("Delete Failed");
    }
  };

  // UPDATE here
  const updateStatus = async (id, status) => {
    try {
      await axios.put(
        `http://localhost:5000/api/admin/appointments/${id}`,
        { status },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      toast.success("Status Updated");
      fetchData("appointments");
    } catch (err) {
      toast.error("Update Failed");
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 p-8">
      <h1 className="text-4xl font-bold mb-8 text-center">Admin Dashboard</h1>

      <div className="flex justify-center gap-4 mb-8 flex-wrap">
        {["users", "doctors", "patients", "appointments"].map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`px-6 py-2 rounded-full capitalize transition font-medium ${
              activeTab === tab
                ? "bg-indigo-600 text-white shadow-lg"
                : "bg-white hover:bg-indigo-100 shadow"
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      <div className="bg-white rounded-xl shadow-lg p-6 overflow-x-auto">
        {data.length === 0 ? (
          <p className="text-center text-gray-500">No Data Found</p>
        ) : activeTab !== "appointments" ? (
          <table className="w-full">
            <thead>
              <tr className="bg-indigo-100 text-left">
                {Object.keys(data[0])
                  .filter((k) => k !== "password")
                  .map((key) => (
                    <th key={key} className="p-3 capitalize">
                      {key}
                    </th>
                  ))}
                <th className="p-3">Actions</th>
              </tr>
            </thead>

            <tbody>
              {data.map((item) => (
                <tr
                  key={item._id}
                  className="border-b hover:bg-gray-50 transition"
                >
                  {Object.entries(item)
                    .filter(([key]) => key !== "password")
                    .map(([key, val]) => (
                      <td key={key} className="p-3">
                        {typeof val === "object" ? JSON.stringify(val) : val}
                      </td>
                    ))}

                  <td className="p-3 flex gap-2">
                    <button
                      onClick={() => handleDelete(item._id)}
                      className="bg-gray-800 text-white px-3 py-1 rounded hover:bg-black"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          // All appointments
          <table className="w-full">
            <thead>
              <tr className="bg-indigo-100 text-left">
                <th className="p-3">ID</th>
                <th className="p-3">Patient</th>
                <th className="p-3">Doctor</th>
                <th className="p-3">Date</th>
                <th className="p-3">Time</th>
                <th className="p-3">Purpose</th>
                <th className="p-3">Status</th>
                <th className="p-3">Actions</th>
              </tr>
            </thead>
            <tbody>
              {data.map((item, index) => (
                <tr
                  key={item._id}
                  className="border-b hover:bg-gray-50 transition"
                >
                  <td className="p-3">{index + 1}</td>
                  <td className="p-3">{item.patient?.name || "N/A"}</td>
                  <td className="p-3">{item.doctor?.name || "N/A"}</td>
                  <td className="p-3">{new Date(item.date).toDateString()}</td>
                  <td className="p-3">{item.time}</td>
                  <td className="p-3">{item.reason}</td>
                  <td className="p-3">
                    <span
                      className={`px-3 py-1 rounded-full text-white text-sm ${
                        item.status === "approved"
                          ? "bg-green-500"
                          : item.status === "rejected"
                          ? "bg-red-500"
                          : "bg-yellow-500"
                      }`}
                    >
                      {item.status}
                    </span>
                  </td>
                  <td className="p-3 flex gap-2 flex-wrap">
                    <button
                      onClick={() => updateStatus(item._id, "approved")}
                      className="bg-green-500 text-white px-3 py-1 rounded hover:bg-green-600"
                    >
                      Approve
                    </button>
                    <button
                      onClick={() => updateStatus(item._id, "rejected")}
                      className="bg-red-500 text-white px-3 py-1 rounded hover:bg-red-600"
                    >
                      Reject
                    </button>
                    <button
                      onClick={() => handleDelete(item._id)}
                      className="bg-gray-800 text-white px-3 py-1 rounded hover:bg-black"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
